package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatPrintRecordTest {

    private CSVFormat csvFormat;
    private Appendable appendable;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
        appendable = mock(Appendable.class);
    }

    @Test
    void testPrintRecordWithMultipleValues() throws IOException {
        csvFormat.printRecord(appendable, "value1", "value2", "value3");
        verify(appendable, atLeastOnce()).append(any(CharSequence.class));
    }

    @Test
    void testPrintRecordWithEmptyValues() throws IOException {
        csvFormat.printRecord(appendable);
        verify(appendable).append("\r\n");
    }

    @Test
    void testPrintRecordWithNullValues() throws IOException {
        csvFormat.printRecord(appendable, (Object) null);
        verify(appendable, atLeastOnce()).append(any(CharSequence.class));
        verify(appendable).append("\r\n");
    }

    @Test
    void testPrintRecordWithMixedNullAndNonNullValues() throws IOException {
        csvFormat.printRecord(appendable, null, "test", null);
        verify(appendable, atLeast(3)).append(any(CharSequence.class));
        verify(appendable).append("\r\n");
    }

    @Test
    void testPrintRecordInvokesPrintPrivateMethod() throws Exception {
        Method printMethod = CSVFormat.class.getDeclaredMethod("print", Object.class, Appendable.class, boolean.class);
        printMethod.setAccessible(true);

        // Use reflection to invoke print method directly
        printMethod.invoke(csvFormat, "value", appendable, true);
        verify(appendable, atLeastOnce()).append(any(CharSequence.class));
    }

    @Test
    void testPrintRecordInvokesPrintlnPrivateMethod() throws Exception {
        Method printlnMethod = CSVFormat.class.getDeclaredMethod("println", Appendable.class);
        printlnMethod.setAccessible(true);

        printlnMethod.invoke(csvFormat, appendable);
        verify(appendable).append("\r\n");
    }
}
